mapper.select:
SELECT bt.id, bt.behavior_code AS behaviorCode, bt.behavior_name AS behaviorName, bt.behavior_category AS behaviorCategory, bt.behavior_nature AS behaviorNature, bt.default_affect_scope AS defaultAffectScope, bt.description, bt.sort_order AS sortOrder, bt.status, bt.created_at AS createdAt, (SELECT COUNT(*) FROM behavior_evaluation_effects bee WHERE bee.behavior_type_id = bt.id AND bee.deleted = 0) AS effectCount FROM behavior_types bt WHERE bt.deleted = 0
AND bt.behavior_code LIKE CONCAT('%', #{query.behaviorCode}, '%')
AND bt.behavior_name LIKE CONCAT('%', #{query.behaviorName}, '%')
AND bt.behavior_category = #{query.behaviorCategory}
AND bt.behavior_nature = #{query.behaviorNature}
AND bt.status = #{query.status}
ORDER BY bt.sort_order, bt.id

SELECT * FROM behavior_types
WHERE deleted = 0 AND status = 1 AND behavior_category = #{category}
ORDER BY sort_order, id

SELECT * FROM behavior_types
WHERE deleted = 0 AND status = 1 AND behavior_nature = #{nature}
ORDER BY sort_order, id
